8	
9	//! Unified Dynamic Shared Memory Example
10	//!
11	//! Demonstrates `DynamicSharedArray<T, ALIGN>` for runtime-sized shared memory.
12	//!
13	//! ## Test Scenarios
14	//!
15	//! 1. **dynamic_smem_basic** - Default alignment (16 bytes)
16	//! 2. **dynamic_smem_partition** - Partitioning multiple arrays
17	//! 3. **dynamic_smem_explicit_align** - Explicit 128-byte alignment (TMA-compatible)
18	//! 4. **dynamic_smem_mixed_align** - Multiple calls with different alignments
19	//!
20	//! ## Key Features Tested
21	//!
22	//! - Per-kernel symbols: Each kernel gets `__dynamic_smem_{kernel_name}`
23	//! - Max alignment: Multiple calls with different ALIGN values use the maximum
24	//! - User-specified alignment: Can specify any power-of-2 alignment
25	//!
26	//! Build and run with:
27	//!   cargo oxide run dynamic_smem
28	
29	use cuda_core::{CudaContext, DeviceBuffer, LaunchConfig};
30	use cuda_device::{DisjointSlice, DynamicSharedArray, gpu_printf, kernel, thread};
31	use cuda_host::cuda_module;
32	
33	// =============================================================================
34	// KERNELS
35	// =============================================================================
36	#[cuda_module]
37	mod kernels {
38	    use super::*;
39	
40	    /// Test 1: Basic dynamic shared memory (default 16-byte alignment).
41	    ///
42	    /// Each thread writes its value to dynamic shared memory, syncs,
43	    /// then reads from its neighbor.
44	    ///
45	    /// PTX output: `.extern .shared .align 16 .b8 __dynamic_smem_dynamic_smem_basic[];`
46	    #[kernel]
47	    pub fn dynamic_smem_basic(data: &[f32], mut out: DisjointSlice<f32>) {
48	        // Default alignment (16 bytes, matches nvcc)
49	        let smem: *mut f32 = DynamicSharedArray::<f32>::get();
50	
51	        let tid = thread::threadIdx_x() as usize;
52	        let gid = thread::index_1d().get();
53	
54	        // Print address from thread 0 (sanity check)
55	        if tid == 0 {
56	            gpu_printf!("[basic] smem addr: {:x} (align 16)\n", smem as u64);
57	        }
58	
59	        unsafe {
60	            *smem.add(tid) = data[gid];
61	        }
62	
63	        thread::sync_threads();
64	
65	        unsafe {
66	            let block_size = thread::blockDim_x() as usize;
67	            let neighbor_idx = (tid + 1) % block_size;
68	            if let Some(out_elem) = out.get_mut(thread::index_1d()) {
69	                *out_elem = *smem.add(neighbor_idx);
70	            }
71	        }
72	    }
73	
74	    /// Test 2: Dynamic shared memory with partitioning.
75	    ///
76	    /// Uses `DynamicSharedArray::offset()` to partition the shared memory into
77	    /// two arrays (A and B).
78	    ///
79	    /// Memory layout:
80	    /// ```text
81	    /// |<-- array_a (N f32s) -->|<-- array_b (N f32s) -->|
82	    /// |        offset 0        |    offset N*4 bytes    |
83	    /// ```
84	    ///
85	    /// PTX output: `.extern .shared .align 16 .b8 __dynamic_smem_dynamic_smem_partition[];`
86	    #[kernel]
87	    pub fn dynamic_smem_partition(a: &[f32], b: &[f32], mut out: DisjointSlice<f32>) {
88	        // First array at offset 0 (default alignment)
89	        let smem_a: *mut f32 = DynamicSharedArray::<f32>::get();
90	
91	        // Second array at offset = N * sizeof(f32)
92	        // For 256 elements: 256 * 4 = 1024 bytes
93	        let smem_b: *mut f32 = DynamicSharedArray::<f32>::offset(1024);
94	
95	        let tid = thread::threadIdx_x() as usize;
96	        let gid = thread::index_1d().get();
97	
98	        // Print addresses from thread 0 (sanity check)
99	        if tid == 0 {
100	            gpu_printf!(
101	                "[partition] smem_a: {:x}, smem_b: {:x} (diff={})\n",
102	                smem_a as u64,
103	                smem_b as u64,
104	                (smem_b as u64) - (smem_a as u64)
105	            );
106	        }
107	
108	        unsafe {
109	            *smem_a.add(tid) = a[gid];
110	            *smem_b.add(tid) = b[gid];
111	        }
112	
113	        thread::sync_threads();
114	
115	        unsafe {
116	            let block_size = thread::blockDim_x() as usize;
117	            let neighbor_idx = (tid + 1) % block_size;
118	            if let Some(out_elem) = out.get_mut(thread::index_1d()) {
119	                *out_elem = *smem_a.add(neighbor_idx) + *smem_b.add(neighbor_idx);
120	            }
121	        }
122	    }
123	
124	    /// Test 3: Explicit 128-byte alignment (TMA-compatible).
125	    ///
126	    /// Demonstrates explicit alignment specification for TMA operations.
127	    ///
128	    /// PTX output: `.extern .shared .align 128 .b8 __dynamic_smem_dynamic_smem_explicit_align[];`
129	    #[kernel]
130	    pub fn dynamic_smem_explicit_align(data: &[f32], mut out: DisjointSlice<f32>) {
131	        // Explicit 128-byte alignment (required for TMA)
132	        let smem: *mut f32 = DynamicSharedArray::<f32, 128>::get();
133	
134	        let tid = thread::threadIdx_x() as usize;
135	        let gid = thread::index_1d().get();
136	
137	        // Print address from thread 0 (sanity check - should be 128-byte aligned)
138	        if tid == 0 {
139	            let addr = smem as u64;
140	            gpu_printf!(
141	                "[explicit] smem addr: {:x} (align 128, mod128={})\n",
142	                addr,
143	                addr % 128
144	            );
145	        }
146	
147	        unsafe {
148	            *smem.add(tid) = data[gid] * 2.0;
149	        }
150	
151	        thread::sync_threads();
152	
153	        unsafe {
154	            let block_size = thread::blockDim_x() as usize;
155	            let neighbor_idx = (tid + 1) % block_size;
156	            if let Some(out_elem) = out.get_mut(thread::index_1d()) {
157	                *out_elem = *smem.add(neighbor_idx);
158	            }
159	        }
160	    }
161	
162	    /// Test 4: Mixed alignments within same kernel (uses maximum).
163	    ///
164	    /// This kernel has multiple DynamicSharedArray calls with different alignments.
165	    /// The compiler pre-pass computes max(16, 128, 256) = 256 and uses that.
166	    ///
167	    /// PTX output: `.extern .shared .align 256 .b8 __dynamic_smem_dynamic_smem_mixed_align[];`
168	    #[kernel]
169	    pub fn dynamic_smem_mixed_align(a: &[f32], b: &[f32], c: &[f32], mut out: DisjointSlice<f32>) {
170	        // Three partitions with different alignment requirements
171	        // The compiler uses max(16, 128, 256) = 256 for the global
172	        let smem_a: *mut f32 = DynamicSharedArray::<f32>::get(); // ALIGN = 16 (default)
173	        let smem_b: *mut f32 = DynamicSharedArray::<f32, 128>::offset(1024); // ALIGN = 128
174	        let smem_c: *mut f32 = DynamicSharedArray::<f32, 256>::offset(2048); // ALIGN = 256
175	
176	        let tid = thread::threadIdx_x() as usize;
177	        let gid = thread::index_1d().get();
178	
179	        // Print addresses from thread 0 (sanity check - base should be 256-byte aligned)
180	        if tid == 0 {
181	            let addr_a = smem_a as u64;
182	            let addr_b = smem_b as u64;
183	            let addr_c = smem_c as u64;
184	            gpu_printf!("[mixed] smem_a: {:x} (mod256={})\n", addr_a, addr_a % 256);
185	            gpu_printf!(
186	                "[mixed] smem_b: {:x} (offset={})\n",
187	                addr_b,
188	                addr_b - addr_a
189	            );
190	            gpu_printf!(
191	                "[mixed] smem_c: {:x} (offset={})\n",
192	                addr_c,
193	                addr_c - addr_a
194	            );
195	        }
