                eprintln!(
                    "Mismatch at {}: expected {} (a+b+c at {}), got {}",
                    i, expected, neighbor_idx, out_result[i]
                );
                std::process::exit(1);
            }
        }
        println!("✓ Mixed alignments (max align 256): correct sum of all three\n");
    }

